13	type escalationFloorFinder interface {
14		Next(actualPower int) (int, error)
15	}
16	
17	func isBudgetExhaustedFailure(report agent.ExecuteBeadReport) bool {
18		return strings.Contains(report.Detail, agent.RateLimitBudgetExhaustedReason)
19	}
20	
21	func nextEscalationFloor(l escalationFloorFinder, actualPower int) (int, error) {
22		if l == nil {
23			return 0, tierescalation.ErrLadderExhausted
24		}
25		floor := actualPower
26		for {
27			next, err := l.Next(floor)
28			if err == nil {
29				return next, nil
30			}
31			var nvp *tierescalation.NoViableProviderError
32			if errors.As(err, &nvp) {
33				floor = nvp.Floor
34				continue
35			}
36			return 0, err
37		}
38	}
