119	// lastFencedBlock returns the body of the LAST ```<lang> … ``` fenced block
120	// in s. lang="" matches any fence ("``` … ```"). Returns ok=false when no
121	// matching fence is found or the fence is unterminated.
122	func lastFencedBlock(s, lang string) (string, bool) {
123		open := "```"
124		if lang != "" {
125			open = "```" + lang
126		}
127		var found string
128		var ok bool
129		idx := 0
130		for {
131			i := indexFromAny(s, idx, open)
132			if i < 0 {
133				break
134			}
135			// Ensure the fence is followed by newline or whitespace (avoid
136			// matching ```jsonc when looking for ```json).
137			afterOpen := i + len(open)
138			if afterOpen < len(s) {
139				c := s[afterOpen]
140				if lang != "" && c != '\n' && c != '\r' && c != ' ' && c != '\t' {
141					idx = i + len(open)
142					continue
143				}
144			}
145			bodyStart := afterOpen
146			// Skip a single trailing newline after the opening fence.
147			if bodyStart < len(s) && s[bodyStart] == '\n' {
148				bodyStart++
149			} else if bodyStart+1 < len(s) && s[bodyStart] == '\r' && s[bodyStart+1] == '\n' {
150				bodyStart += 2
151			}
152			// Find closing fence.
153			j := strings.Index(s[bodyStart:], "```")
154			if j < 0 {
155				break
156			}
157			body := s[bodyStart : bodyStart+j]
158			// Strip a single trailing newline before the closing fence.
159			body = strings.TrimRight(body, "\n\r")
160			found = body
161			ok = true
162			idx = bodyStart + j + 3
163		}
164		return found, ok
165	}
